@@ -7159,6 +7236,10 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   if (Options.ConvertSwitchRangeToICmp && turnSwitchRangeIntoICmp(SI, Builder))
     return requestResimplify();

+  // Try to turn a switch on a cmp intrinsic into an icmp + branch.
+  if (turnSwitchOfCmpIntrinsicIntoICmp(SI, Builder))
+    return requestResimplify();
+
