/// Turn a switch on a comparison intrinsic result into an icmp + branch.
/// The comparison intrinsic (llvm.ucmp/llvm.scmp) returns -1 for less than,
/// 0 for equal, and 1 for greater than. This function recognizes patterns
/// where the switch cases can be folded into a single comparison.
bool SimplifyCFGOpt::turnSwitchOfCmpIntrinsicIntoICmp(SwitchInst *SI,
                                                      IRBuilder<> &Builder) {
  assert(SI->getNumCases() > 1 && "Degenerate switch?");

  Value *Cond = SI->getCondition();
  auto *CmpII = dyn_cast<CmpIntrinsic>(Cond);
  if (!CmpII)
    return false;

  // Only handle scalar comparisons for now.
  if (Cond->getType()->isVectorTy())
    return false;

  Value *LHS = CmpII->getLHS();
  Value *RHS = CmpII->getRHS();
  CmpInst::Predicate PredGT = CmpII->getGTPredicate();
  CmpInst::Predicate PredLT = CmpII->getLTPredicate();

  // Determine which destination each comparison result maps to.
  // -1 (LT), 0 (EQ), 1 (GT). Default destination catches any unlisted case.
  BasicBlock *DestLT = nullptr;
  BasicBlock *DestEQ = nullptr;
  BasicBlock *DestGT = SI->getDefaultDest();

  for (auto Case : SI->cases()) {
    int64_t Val = Case.getCaseValue()->getSExtValue();
    BasicBlock *Dest = Case.getCaseSuccessor();
    if (Val == -1)
      DestLT = Dest;
    else if (Val == 0)
      DestEQ = Dest;
    else if (Val == 1)
      DestGT = Dest;
  }

  // We need all three destinations to be defined (possibly same).
  if (!DestLT || !DestEQ)
    return false;

  // Now check for patterns where we can reduce to a single icmp.
  // Pattern 1: LT and EQ go to same dest, GT goes to different dest.
  // Result: icmp gt (true -> DestGT, false -> DestLT/EQ)
  if (DestLT == DestEQ && DestGT != DestLT) {
    Value *Cmp = Builder.CreateICmp(PredGT, LHS, RHS, "cmp");
    BranchInst::Create(DestGT, DestLT, Cmp, SI);
    SI->eraseFromParent();
    return true;
  }

  // Pattern 2: GT and EQ go to same dest, LT goes to different dest.
  // Result: icmp lt (true -> DestLT, false -> DestGT/EQ)
  if (DestGT == DestEQ && DestLT != DestGT) {
    Value *Cmp = Builder.CreateICmp(PredLT, LHS, RHS, "cmp");
    BranchInst::Create(DestLT, DestGT, Cmp, SI);
    SI->eraseFromParent();
    return true;
  }

  // Pattern 3: LT and GT go to same dest, EQ goes to different dest.
  // Result: icmp ne (true -> DestLT/GT, false -> DestEQ)
  if (DestLT == DestGT && DestEQ != DestLT) {
    Value *Cmp = Builder.CreateICmp(ICmpInst::ICMP_NE, LHS, RHS, "cmp");
    BranchInst::Create(DestLT, DestEQ, Cmp, SI);
    SI->eraseFromParent();
    return true;
  }

  // Pattern 4: All three go to different destinations - can't simplify to single icmp.
  // Pattern 5: All three go to same destination - should have been folded earlier.
  return false;
}

CODEEOF"}

